    vendAgingReportDPParameters.custVendTransAging = custVendTransAging;

    vendAgingReportDPParameters.reverseAmountsAndHeadings = _reverseAmountsAndHeadings;
    vendAgingReportDPParameters.ledgerCurrencySelection = contract.parmCurrencySelection();
    vendAgingReportDPParameters.headingDate = headingDate;
    vendAgingReportDPParameters.heading01 = heading01;
    vendAgingReportDPParameters.heading011 = heading011;
    vendAgingReportDPParameters.heading02 = heading02;
    vendAgingReportDPParameters.heading02Text = heading02Text;
    vendAgingReportDPParameters.heading021 = heading021;
    vendAgingReportDPParameters.heading03 = heading03;
    vendAgingReportDPParameters.heading031 = heading031;
    vendAgingReportDPParameters.heading04 = heading04;
    vendAgingReportDPParameters.heading041 = heading041;
    vendAgingReportDPParameters.heading05 = heading05;
    vendAgingReportDPParameters.heading051 = heading051;
    vendAgingReportDPParameters.heading06 = heading06;
    vendAgingReportDPParameters.heading061 = heading061;
    vendAgingReportDPParameters.heading07 = heading07;
    vendAgingReportDPParameters.heading071 = heading071;
    vendAgingReportDPParameters.heading08   = heading08;
    vendAgingReportDPParameters.heading081  = heading081;
    vendAgingReportDPParameters.heading09   = heading09;
    vendAgingReportDPParameters.heading091  = heading091;
    vendAgingReportDPParameters.heading10   = heading10;
    vendAgingReportDPParameters.heading101  = heading101;
    vendAgingReportDPParameters.heading10Text = heading10Text;
    vendAgingReportDPParameters.headingAgingBucketDescription02 = headingAgingBucketDescription02;
    vendAgingReportDPParameters.headingAgingBucketDescription03 = headingAgingBucketDescription03;
    vendAgingReportDPParameters.headingAgingBucketDescription04 = headingAgingBucketDescription04;
    vendAgingReportDPParameters.headingAgingBucketDescription05 = headingAgingBucketDescription05;
    vendAgingReportDPParameters.headingAgingBucketDescription06 = headingAgingBucketDescription06;
    vendAgingReportDPParameters.headingAgingBucketDescription07 = headingAgingBucketDescription07;
    vendAgingReportDPParameters.headingAgingBucketDescription08 = headingAgingBucketDescription08;
    vendAgingReportDPParameters.headingAgingBucketDescription09 = headingAgingBucketDescription09;
    vendAgingReportDPParameters.headingAgingBucketDescription10 = headingAgingBucketDescription10;
    vendAgingReportDPParameters.headingAgingBucketDescription11 = headingAgingBucketDescription11;
    vendAgingReportDPParameters.headingAccount = "@SYS24500";
    vendAgingReportDPParameters.headingName = "@SYS7399";
    vendAgingReportDPParameters.balance = 100;
    vendAgingReportDPParameters.asOfDate = strFmt("@SYS84682", date2StrUsr(contract.parmBalanceAsOfDate(), DateFlags::FormatAll), contract.parmDateTransactionDuedate());

    ETG_VendAgingReportTmpFromVendTmpAccountSum vendAgingReportTmpFromVendTmpAccountSum = ETG_VendAgingReportTmpFromVendTmpAccountSum::newFromCustAgingReportDP(vendAgingReportDPParameters);
    vendAgingReportTmpFromVendTmpAccountSum.execute();
}

public boolean parmUseDefaultTransactionOnly(boolean _useDefaultTransOnly = useDefaultTransOnly)
{
    useDefaultTransOnly = true;
    return useDefaultTransOnly;
}

/// <summary>
/// Processes the report business logic.
/// </summary>
/// <remarks>
/// This method is used to process the report business logic which is used by the <c>VendAgingReport</c> report.
/// </remarks>
public void processReport()
{
    QueryRun qr;
    ForwardBackwardPrinting tmpDirection;
    boolean reverseAmountsAndHeadings;
    RecordInsertList tmpTableRecordList = new RecordInsertList(tableNum(ETG_VendAgingReportTmp), true, true, true, false, true, vendAgingReportTmp);

    contract = this.parmDataContract() as ETG_VendAgingReportContract;

    financialDimensions             = contract.parmFinancialDimensions();
    financialDimSet                 = contract.parmFinancialDimSet();

    qr = new QueryRun(this.parmQuery());

    if (!contract.parmZeroDate())
    {
        // When zero date is not given then use the system session date.
        contract.parmZeroDate(DateTimeUtil::getSystemDate(DateTimeUtil::getUserPreferredTimeZone()));
    }

    if (!contract.parmBalanceAsOfDate())
    {
        // When the balance as of date is not given then use the max date.
        contract.parmBalanceAsOfDate(dateMax());
    }

    if (contract.parmAgingBuckets())
    {
        // Force layout direction to backwards,
        // the actual direction of the columns is done in the construct method of the class: CustVendBalanceList
        tmpDirection = StatRepInterval::find(contract.parmAgingBuckets()).PrintDirection;
    }
    else
    {
        tmpDirection = contract.parmDirection();
    }

    reverseAmountsAndHeadings = this.getReverseAmountsAndHeadings(contract.parmAgingBuckets(), tmpDirection);

    custVendBalanceList = ETG_CustVendBalanceList::construct(SysModule::Vend,
                                                            contract.parmDateTransactionDuedate(),
                                                            contract.parmInterval(),
                                                            contract.parmBalanceAsOfDate(),
                                                            contract.parmZeroDate(),
                                                            contract.parmPayments(),
                                                            contract.parmPeriod(),
                                                            tmpDirection,
                                                            contract.parmAgingBuckets(),
                                                            NoYes::Yes,
                                                            contract.parmDetailed(),
                                                            null,
                                                            NoYes::No,
                                                            contract.parmExcludeZeroBalanceVendor(),
                                                            !contract.parmPrintZeroOrNegative());

    custVendBalanceList.calculateDetailsForMultiple(qr, CustVendAgingQueryConverter::convertVendors(qr.query()), contract.parmIncludeAmountCur());
    tmpAccountSum = custVendBalanceList.initTmpAccountSum();

    this.initHeadingValues();

    this.insertVendAgingReportTmp(reverseAmountsAndHeadings, tmpTableRecordList);

    if (contract.parmDetailed())
    {
        this.updateVendAgingReportTmp();
    }
    if(!contract.parmDetailed())
    {
        this.updateVendAgingReportTmpNonDet();
    }

}

public Description getFinDimValue(DimensionDefault _defaultDimension, Name     _dimensionName)
{
    DimensionAttributeValueSetStorage   dimStorage;
    DimensionAttribute                  dimAttribute;
    DimensionValue                      displayValue = "";
    Description                         dimDescription = "";
    int                                 i;

    dimStorage = DimensionAttributeValueSetStorage::find(_defaultDimension);
    for (i= 1 ; i<= dimStorage.elements() ; i++)
    {
        dimAttribute    = DimensionAttribute::find(dimStorage.getAttributeByIndex(i));

        if(dimAttribute.Name == _dimensionName)
        {
            displayValue    = dimStorage.getDisplayValueByIndex(i);
            dimDescription  = DimensionFinancialTag::findByFinancialTagCategoryAndValue(dimAttribute.financialTagCategory(), displayValue).Description;
            if (dimDescription == "")
            {
                dimDescription  = this.getFinDimValueDescription(dimAttribute.ViewName, displayValue);
            }
        }
    }

    return  dimDescription;
}

public Description getFinDimValueDescription(TableNameShort     _ViewName, DimensionValue   _displayValue)
{
    DimAttributeInventTable         inventTable;
    DimAttributeHcmWorker           worker;
    DimAttributeCustTable           custTable;
    DimAttributeVendTable           dimVendTable;
    DimAttributeAssetTable          assetTable;
    DimAttributeOMBusinessUnit      businessUnit;
    DimAttributeOMCostCenter        costCenter;
    DimAttributeOMDepartment        department;
    Description                     dimDescription = "";

    switch (_ViewName)
    {
        case  "DimAttributeInventTable":
            select Name from inventTable
                where inventTable.value == _displayValue;
            dimDescription = inventTable.Name;
            break;
        case  "DimAttributeHcmWorker":
            select Name from worker
                where worker.value == _displayValue;
            dimDescription = worker.Name;
            break;
        case  "DimAttributeCustTable":
            select Name from custTable
                where custTable.value == _displayValue;
            dimDescription = custTable.Name;
            break;
        case  "DimAttributeVendTable":
            select Name from dimVendTable
                where dimVendTable.value == _displayValue;
            dimDescription = dimVendTable.Name;
            break;
        case  "DimAttributeAssetTable":
            select Name from assetTable
                where assetTable.value == _displayValue;
            dimDescription = assetTable.Name;
            break;
        case  "DimAttributeOMBusinessUnit":
            select Name from businessUnit
                where businessUnit.value == _displayValue;
            dimDescription = businessUnit.Name;
            break;
        case  "DimAttributeOMCostCenter":
            select Name from costCenter
                where costCenter.value == _displayValue;
            dimDescription = costCenter.Name;
            break;
        case  "DimAttributeOMDepartment":
            select Name from department
                where department.value == _displayValue;
            dimDescription = department.Name;
            break;
    }

    return      dimDescription;
}

public void updateVendAgingReportTmpNonDet()
{
    VendTrans                       vendTrans,vendTransNondetTot,vendTransNondet,vendTransNondetLoc,vendTransNondetBal9,vendTransNondetBal10;
    FinancialDimensionSetEntity     financialDimensionSetEntity;

    ttsbegin;
    while select forupdate vendAgingReportTmp
    {
        /*if(this.headingDate() == "Transaction date")
        {
            vendAgingReportTmp.TransDate = vendTrans.TransDate;
        }
        if(this.headingDate()== "Document date")
        {
            vendAgingReportTmp.TransDate = vendTrans.DocumentDate;
        }
        if(this.headingDate() == "Due date")
        {
            vendAgingReportTmp.TransDate = vendTrans.DueDate;
        }*/

        select sum(AmountMST) from vendTransNondet
            where vendTransNondet.AccountNum == vendAgingReportTmp.AccountNum &&
                  vendTransNondet.TransDate  <=  contract.parmBalanceAsOfDate();

        vendAgingReportTmp.Balance01NonDet = vendTransNondet.AmountMST;

        select sum(AmountMST) from vendTransNondetTot
            where vendTransNondetTot.TransDate  <  contract.parmBalanceAsOfDate() &&
                  vendTransNondetTot.AccountNum ==  vendAgingReportTmp.AccountNum;
        vendAgingReportTmp.Total += vendTransNondetTot.AmountMST;

        select sum(AmountMST),TransDate from vendTransNondetLoc 
            where vendTransNondetLoc.AccountNum ==  vendAgingReportTmp.AccountNum &&
                  vendTransNondetLoc.CurrencyCode ==  vendAgingReportTmp.CurrencyCode &&
                  (vendTransNondetLoc.TransDate  >=  vendAgingReportTmp.Heading8  &&
                  vendTransNondetLoc.TransDate  <=  vendAgingReportTmp.Heading18) ;
        if(vendTransNondetLoc)
        {
            vendAgingReportTmp.Balance08NonDet = vendTransNondetLoc.AmountMST;
        }
        select sum(AmountMST),TransDate from vendTransNondetBal9
            where vendTransNondetBal9.AccountNum ==  vendAgingReportTmp.AccountNum &&
                  vendTransNondetBal9.CurrencyCode ==  vendAgingReportTmp.CurrencyCode &&
                  (vendTransNondetBal9.TransDate  >=  vendAgingReportTmp.Heading9  &&
                  vendTransNondetBal9.TransDate  <=  vendAgingReportTmp.Heading19) ;
        if(vendTransNondetBal9)
        {
            vendAgingReportTmp.Balance09NonDet = vendTransNondetBal9.AmountMST;
        }
        select sum(AmountMST),TransDate from vendTransNondetBal10
            where vendTransNondetBal10.AccountNum ==  vendAgingReportTmp.AccountNum &&
                    vendTransNondetBal10.CurrencyCode ==  vendAgingReportTmp.CurrencyCode &&
                  //(vendTransNondetBal10.TransDate  >=  str2Date(vendAgingReportTmp.Heading10,1)  &&
                  vendTransNondetBal10.TransDate  <=  vendAgingReportTmp.Heading20 ;
        if(vendTransNondetBal10)
        {
            vendAgingReportTmp.Balance10NonDet = vendTransNondetBal10.AmountMST;
        }
        //ETGACFParameters acfParameters = ETGACFParameters::find();
        //GeneralJournalAccountEntry generalJournalAccountEntry
        //select firstOnly 
        //from generalJournalAccountEntry
        //    where generalJournalAccountEntry.Voucher == vendAgingReportTmp.Voucher;

        //if (generalJournalAccountEntry.Voucher )
        //{
        //    vendAgingReportTmp.ETGCommodity = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValueCodeOnlyETG(generalJournalAccountEntry.OffsetDefaultDimension,acfParameters.MainCommodity);
        //    vendAgingReportTmp.ETGSubCommodity = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValueCodeOnlyETG(generalJournalAccountEntry.OffsetDefaultDimension,acfParameters.SubCommodity);
        //vendAgingReportTmp.ETGCommodity = ETGGeneralJournalAccountEntry_Extension::vertical;
        //}

        GeneralJournalEntry journalEntry;
        GeneralJournalAccountEntry accountEntry;

        select firstOnly journalEntry
            where journalEntry.SubledgerVoucher == vendAgingReportTmp.Voucher;

        if (journalEntry.RecId)
        {
            select firstOnly accountEntry
            where accountEntry.GeneralJournalEntry == journalEntry.RecId;

            if (accountEntry.RecId)
            {
                vendAgingReportTmp.ETGCommodity = ETGGeneralJournalAccountEntry_Extension::commodity(accountEntry);
                //vendAgingReportTmp.ETGSubCommodity = ETGGeneralJournalAccountEntry_Extension::su(accountEntry);
                vendAgingReportTmp.ETGVertical = ETGGeneralJournalAccountEntry_Extension::Vertical(accountEntry);
                vendAgingReportTmp.ETGSubVertical = ETGGeneralJournalAccountEntry_Extension::subVertical(accountEntry);
            }
        }

            vendAgingReportTmp.update();
    }
    ttscommit;
}

